 184	    store: &super::StateStore,
 185	    run_id: &str,
 186	    receipt: &crate::state_store::RunGraphDispatchReceipt,
 187	) -> Result<(), String> {
 188	    let status = store
 189	        .run_graph_status(run_id)
 190	        .await
 191	        .map_err(|error| {
 192	            format!(
 193	                "Failed to read persisted run-graph state for `{run_id}` while reconciling explicit continuation binding: {error}"
 194	            )
 195	        })?;
 196	    if status.status != "completed" {
 197	        return Ok(());
 198	    }
 199	
 200	    let binding = store
 201	        .run_graph_continuation_binding(run_id)
 202	        .await
 203	        .map_err(|error| {
 204	            format!("Failed to read explicit continuation binding for `{run_id}`: {error}")
 205	        })?;
 206	    let Some(binding) = binding else {
 207	        return Ok(());
 208	    };
 209	    if binding.status != "bound"
 210	        || binding.active_bounded_unit["kind"].as_str() != Some("task_graph_task")
 211	    {
 212	        return Ok(());
 213	    }
 214	
 215	    let bound_task_id = binding.active_bounded_unit["task_id"]
 216	        .as_str()
 217	        .filter(|value| !value.trim().is_empty())
 218	        .unwrap_or(binding.task_id.as_str());
 219	    let Some(packet_path) = receipt.dispatch_packet_path.as_deref() else {
 220	        return Ok(());
 221	    };
 222	    let packet = read_dispatch_packet(packet_path)?;
 223	    validate_receipt_packet_pair(receipt, &packet, packet_path, "dispatch packet")?;
 224	    let Some(lineage_task_id) = persisted_dispatch_packet_lineage_task_id(&packet) else {
 225	        return Ok(());
 226	    };
 227	    if lineage_task_id == bound_task_id {
 228	        return Ok(());
 229	    }
 230	
 231	    Err(format!(
 232	        "Completed run `{run_id}` has explicit continuation binding to task_graph_task `{bound_task_id}`, but persisted dispatch packet lineage at `{packet_path}` still points to task `{lineage_task_id}`. Resume must fail closed until a fresh dispatch packet is recorded for the bound task."
